void BEVFusionNode::cameraInfoCallback(
  const sensor_msgs::msg::CameraInfo & msg, std::size_t camera_id)
{
  camera_data_ptrs_[camera_id]->update_camera_info(msg);
  std::size_t num_valid_intrinsics = std::count_if(
    camera_data_ptrs_.begin(), camera_data_ptrs_.end(),
    [](const auto & camera_data) { return camera_data->is_camera_info_available(); });

  intrinsics_available_ = num_valid_intrinsics == camera_data_ptrs_.size();

  if (
    lidar2camera_extrinsics_[camera_id].has_value() || !lidar_frame_.has_value() ||
    extrinsics_available_) {
    return;
  }

  try {
    geometry_msgs::msg::TransformStamped transform_stamped;
    transform_stamped =
      tf_buffer_.lookupTransform(msg.header.frame_id, *lidar_frame_, msg.header.stamp);

    Eigen::Matrix4f lidar2camera_transform =
      tf2::transformToEigen(transform_stamped.transform).matrix().cast<float>();

    Matrix4f lidar2camera_rowmajor_transform = lidar2camera_transform.eval();
    lidar2camera_extrinsics_[camera_id] = lidar2camera_rowmajor_transform;
  } catch (tf2::TransformException & ex) {
    RCLCPP_WARN_STREAM(rclcpp::get_logger("bevfusion"), ex.what());
    return;
  }

  std::size_t num_valid_extrinsics = std::count_if(
    lidar2camera_extrinsics_.begin(), lidar2camera_extrinsics_.end(),
    [](const auto & opt) { return opt.has_value(); });

  extrinsics_available_ = num_valid_extrinsics == lidar2camera_extrinsics_.size();
}

void CameraData::update_camera_info(const sensor_msgs::msg::CameraInfo & camera_info_msg)
{
  // Update camera info message
  camera_info_ = camera_info_msg;

  // Dont need to compute matrices and undistortion if it's not enabled
  if (!image_pre_processing_params_.run_image_undistortion) {
    return;
  }

  // Check if undistorted map x and y are already computed
  if (
    camera_matrices_ptr_->undistorted_map_x_d_ != nullptr &&
    camera_matrices_ptr_->undistorted_map_y_d_ != nullptr) {
    return;
  }

  // Update camera matrices
  camera_matrices_ptr_->update_camera_matrices(camera_info_msg);

  // Compute undistorted map x and y
  camera_matrices_ptr_->compute_undistorted_map_x_y(stream_);
}

void CameraMatrices::update_camera_matrices(const sensor_msgs::msg::CameraInfo & camera_info)
{
  // Create camera matrix K from camera_info
  K =
    (cv::Mat_<double>(3, 3) << camera_info.k[0], camera_info.k[1], camera_info.k[2],
     camera_info.k[3], camera_info.k[4], camera_info.k[5], camera_info.k[6], camera_info.k[7],
     camera_info.k[8]);

  // Create distortion coefficients matrix D from camera_info
  const auto & d_vec = camera_info.d;
  D = cv::Mat(1, static_cast<int>(d_vec.size()), CV_64F);
  for (size_t i = 0; i < d_vec.size(); ++i) {
    D.at<double>(0, static_cast<int>(i)) = d_vec[i];
  }

  // Create projection matrix P from camera_info (first 3x3 part)
  P =
    (cv::Mat_<double>(3, 3) << camera_info.p[0], camera_info.p[1], camera_info.p[2],
     camera_info.p[4], camera_info.p[5], camera_info.p[6], camera_info.p[8], camera_info.p[9],
     camera_info.p[10]);

  // Use full resolution for both input and output (no downsampling)
  map_width = camera_info.width;
  map_height = camera_info.height;
}

void CameraMatrices::compute_undistorted_map_x_y(cudaStream_t stream)
{
  undistorted_map_x_d_ = autoware::cuda_utils::make_unique<float[]>(map_width * map_height);
  undistorted_map_y_d_ = autoware::cuda_utils::make_unique<float[]>(map_width * map_height);

  // Compute undistortion maps for full resolution
  cv::Mat undistort_map_x, undistort_map_y;
  cv::initUndistortRectifyMap(
    K, D, cv::Mat(), P, cv::Size(map_width, map_height), CV_32FC1, undistort_map_x,
    undistort_map_y);

  // Always sync the data to the GPU since it only runs once for every camera
  CHECK_CUDA_ERROR(cudaMemcpyAsync(
    undistorted_map_x_d_.get(), undistort_map_x.data, map_width * map_height * sizeof(float),
    cudaMemcpyHostToDevice, stream));
  CHECK_CUDA_ERROR(cudaMemcpyAsync(
    undistorted_map_y_d_.get(), undistort_map_y.data, map_width * map_height * sizeof(float),
    cudaMemcpyHostToDevice, stream));

  matrices_ready = true;
}
